  ('00000000-0000-0000-0005-000000000007', '00000000-0000-0000-0001-000000000003', '감염관리', '보호구', 'hard', 'multiple_choice', '격리 병실 출입 시 보호구 착용 순서로 가장 적절한 것은?', 1, '일반적으로 가운, 마스크, 고글, 장갑 순서로 착용한다.', 'published', '2026-06-02T00:00:00Z', '2026-06-02T00:00:00Z'),
